const content = [
        `## ${emoji} Feedback: ${entry.title}`,
        `**Category:** ${entry.category.replace(/([A-Z])/g, " $1").trim()}`,
        `**Wallet:** ${walletLine}`,
        `**Time:** ${entry.timestamp}`,
        ``,
        entry.description,
      ].join("\n");

      await fetch(DISCORD_WEBHOOK, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ content }),
      });
